// ❌ BAD - loads entire Orders table into memory before filtering
IEnumerable<Order> allOrders = dbContext.Orders.AsEnumerable();
var bigOrders = allOrders.Where(o => o.Total > 500);

// ✅ GOOD - single SQL with WHERE + ORDER BY runs on the database
List<Order> bigOrders = await dbContext.Orders
    .Where(o => o.Total > 500)
    .OrderBy(o => o.CreatedAt)
    .ToListAsync();

// ❌ BAD - N+1: one SELECT per customer fires inside the loop
var customers = await ctx.Customers.ToListAsync();
foreach (var c in customers)
    Console.WriteLine(c.Orders.Count); // triggers SELECT per customer

// ✅ GOOD - single JOIN loads customers and orders together
var customers = await ctx.Customers
    .Include(c => c.Orders)
    .AsSplitQuery()
    .ToListAsync();
foreach (var c in customers)
    Console.WriteLine(c.Orders.Count); // no extra queries

// ❌ BAD - tracking query on a read-only dashboard loads snapshots for every row
var products = await ctx.Products
    .Where(p => p.CategoryId == categoryId)
    .ToListAsync();

// ✅ GOOD - no tracking for read-only query, less memory and faster materialization
var products = await ctx.Products
    .AsNoTracking()
    .Where(p => p.CategoryId == categoryId)
    .OrderBy(p => p.Name)
    .ToListAsync();

// ❌ BAD - custom method forces full table load in EF Core 3+ (throws)
var orders = await ctx.Orders
    .Where(o => FormatOrderRef(o.Reference) == inputRef)
    .ToListAsync();

// ✅ GOOD - filter in SQL first, then apply C# logic in memory on small result set
var orders = await ctx.Orders
    .Where(o => o.Status == OrderStatus.Active)  // SQL
    .AsEnumerable()                               // explicit boundary
    .Where(o => FormatOrderRef(o.Reference) == inputRef) // C# in memory
    .ToList();

// ❌ BAD - loads full Order entities with all columns and tracking overhead for a list view
var orders = await ctx.Orders
    .Where(o => o.CustomerId == customerId)
    .ToListAsync();

// ✅ GOOD - targeted projection emits only required columns, no tracking, COUNT in SQL
var summaries = await ctx.Orders
    .Where(o => o.CustomerId == customerId)
    .Select(o => new OrderSummaryDto
    {
        Id = o.Id,
        Total = o.Total,
        ItemCount = o.Items.Count,
        Status = o.Status
    })
    .OrderByDescending(o => o.Id)
    .ToListAsync();

// ❌ BAD - paying expression-tree parsing and cache lookup on every call in a hot path
public Task<Customer?> GetByEmailAsync(string email) =>
    _ctx.Customers.AsNoTracking().SingleOrDefaultAsync(c => c.Email == email);

// ✅ GOOD - compiled once at startup, delegate called directly with zero translation overhead
private static readonly Func<AppDbContext, string, Task<Customer?>> FindByEmail =
    EF.CompileAsyncQuery((AppDbContext ctx, string email) =>
        ctx.Customers
            .AsNoTracking()
            .SingleOrDefault(c => c.Email == email));

public Task<Customer?> GetByEmailAsync(string email) =>
    FindByEmail(_ctx, email);

// ❌ BAD - no visibility into SQL in development, can't diagnose slow queries
builder.Services.AddDbContext<AppDbContext>(opt =>
    opt.UseSqlServer(connStr));

// ✅ GOOD - structured SQL logging with dev-only sensitive data
builder.Services.AddDbContext<AppDbContext>(opt =>
    opt.UseSqlServer(connStr)
       .UseLoggerFactory(LoggerFactory.Create(b => b.AddConsole()))
       .EnableSensitiveDataLogging()  // DEV ONLY
       .EnableDetailedErrors());      // DEV ONLY

// ❌ BAD - SQL injection risk: user input directly in the SQL string
var orders = ctx.Orders.FromSqlRaw(
    $"SELECT * FROM Orders WHERE CustomerId = '{customerId}'").ToList();

// ✅ GOOD - interpolated string is auto-parameterized, safe from injection
decimal minAmount = 200m;
var orders = await ctx.Orders
    .FromSqlInterpolated($"""
        SELECT * FROM dbo.Orders
        WHERE Total > {minAmount}
          AND Status = 'Active'
        """)
    .AsNoTracking()
    .OrderBy(o => o.CreatedAt)
    .ToListAsync();

// ❌ BAD - single JOIN across Students and Assignments causes Cartesian explosion
var courses = await ctx.Courses
    .Include(c => c.Students)
    .Include(c => c.Assignments)
    .ToListAsync();

// ✅ GOOD - AsSplitQuery issues one SELECT per collection, stitches in memory
var courses = await ctx.Courses
    .Include(c => c.Students)
    .Include(c => c.Assignments)
    .AsSplitQuery()
    .AsNoTracking()
    .ToListAsync();
